#!/usr/bin/env node
/**
 * .github/scripts/generate-api-docs.js
 * Versión CI del generador de API docs.
 * Extrae JSDoc de src/app/api/ y supabase/functions/.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '../..');

function scanForFiles(dir, ext) {
  const results = [];
  if (!fs.existsSync(dir)) return results;
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) results.push(...scanForFiles(full, ext));
    else if (entry.name.endsWith(ext)) results.push(full);
  }
  return results;
}

function extractJsDoc(src) {
  const match = src.match(/\/\*\*([\s\S]*?)\*\//);
  if (!match) return '';
  return match[0]
    .replace(/^\/\*\*/, '').replace(/\*\/$/, '')
    .split('\n').map((l) => l.replace(/^\s*\*\s?/, '')).join('\n').trim();
}

const apiDir = path.join(ROOT, 'src/app/api');
const functionsDir = path.join(ROOT, 'supabase/functions');

let content = '# API Reference\n\n*Auto-generated by CI — do not edit manually*\n\n';

if (fs.existsSync(apiDir)) {
  content += '## Next.js API Routes\n\n';
  for (const route of scanForFiles(apiDir, 'route.ts')) {
    const rel = route.replace(apiDir, '').replace('/route.ts', '') || '/';
    const jsdoc = extractJsDoc(fs.readFileSync(route, 'utf8'));
    content += `### \`${rel}\`\n${jsdoc || '_No description_'}\n\n`;
  }
}

if (fs.existsSync(functionsDir)) {
  content += '## Supabase Functions\n\n';
  for (const fn of fs.readdirSync(functionsDir).filter(
    (d) => fs.statSync(path.join(functionsDir, d)).isDirectory()
  )) {
    const indexPath = path.join(functionsDir, fn, 'index.ts');
    if (fs.existsSync(indexPath)) {
      const jsdoc = extractJsDoc(fs.readFileSync(indexPath, 'utf8'));
      content += `### \`${fn}\`\n${jsdoc || '_No description_'}\n\n`;
    }
  }
}

fs.writeFileSync(path.join(ROOT, 'docs/api-reference.md'), content);
console.log('✅ docs/api-reference.md generated');
